class MedianFinder {
public:
    priority_queue<int, vector<int>, less<int>> queMin;    // 大顶堆：存较小的一半，堆顶是这半的最大值
    priority_queue<int, vector<int>, greater<int>> queMax; // 小顶堆：存较大的一半，个数等于 queMin 或少 1

    MedianFinder() {}

    void addNum(int num) {
        if (queMin.empty() || num <= queMin.top()) {
            queMin.push(num);
            if (queMax.size() + 1 < queMin.size()) {
                queMax.push(queMin.top());
                queMin.pop();
            }
        } else {
            queMax.push(num);
            if (queMax.size() > queMin.size()) {
                queMin.push(queMax.top());
                queMax.pop();
            }
        }
    }

    double findMedian() {
        if (queMin.size() > queMax.size()) {
            return queMin.top();
        }
        return (queMin.top() + queMax.top()) / 2.0;
    }
};
